#!/usr/bin/env -S npx tsx
/* eslint-disable no-console -- one-shot CLI: console is the UI */

/**
 * Dump the live OpenAPI spec generated by `@fastify/swagger` to a JSON file.
 *
 * Usage:
 *   bin/dump-openapi.ts [--out <path>]
 *
 * Defaults to `server/openapi.json` (committed to the repo). The react-app
 * codegen (#167 PR D) reads from there to keep the typed client in lockstep
 * with the server contract.
 *
 * Boots the app (which initialises models against the dummy driver so the
 * server can start without a real DB) just long enough to call
 * `app.swagger()`, then exits.
 */

import { writeFileSync } from "node:fs";
import { resolve } from "node:path";
import yargs from "yargs";
import { hideBin } from "yargs/helpers";

const args = await yargs(hideBin(process.argv))
  .usage("Usage: $0 [--out <path>]")
  .option("out", {
    type: "string",
    describe: "Output file path (default: server/openapi.json)",
    default: resolve(import.meta.dirname, "..", "openapi.json"),
  })
  .strict()
  .help()
  .parse();

process.env.DB_DRIVER ??= "dummy";
process.env.NODE_ENV ??= "test";

const { app, init } = await import("../app.js");
await init();

const spec = app.swagger();
writeFileSync(args.out, JSON.stringify(spec, null, 2) + "\n", "utf8");
console.log(`OpenAPI spec written to ${args.out}`);

await app.close();
